#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[2015];
        scanf("%s", S);
        int N = strlen(S);
        const char *pat = "CHEF";
        for (int i = N - 4; i >= 0; --i) {
            int ok = 1;
            for (int j = 0; j < 4; ++j) {
                char c = S[i + j];
                if (c != '?' && c != pat[j]) { ok = 0; break; }
            }
            if (ok) {
                for (int j = 0; j < 4; ++j) S[i + j] = pat[j];
            }
        }
        for (int i = 0; i < N; ++i) if (S[i] == '?') S[i] = 'A';
        printf("%s\n", S);
    }
    return 0;
}

