import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data: return
    t = int(data[0])
    pat = 'CHEF'
    out = []
    for i in range(1, t+1):
        s = list(data[i].strip())
        n = len(s)
        for pos in range(n-4, -1, -1):
            ok = True
            for j in range(4):
                if s[pos+j] != '?' and s[pos+j] != pat[j]:
                    ok = False
                    break
            if ok:
                for j in range(4):
                    s[pos+j] = pat[j]
        for k in range(n):
            if s[k] == '?':
                s[k] = 'A'
        out.append(''.join(s))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

